record.field:
instance = env.user.woo_active_instance_id
if not instance:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Sin instancia seleccionada',
            'message': 'Por favor, selecciona una instancia desde el menú Instancias.',
            'type': 'warning',
            'sticky': False,
        },
    }
else:
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Ordenes - %s' % instance.name,
        'res_model': 'odoo.wp.sync',
        'view_mode': 'tree,form',
        'domain': [('instance_id', '=', instance.id)],
        'context': {'default_instance_id': instance.id},
    }

instance = env.user.woo_active_instance_id
if not instance:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Sin instancia seleccionada',
            'message': 'Por favor, selecciona una instancia desde el menú Instancias.',
            'type': 'warning',
            'sticky': False,
        },
    }
else:
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Productos WooCommerce - %s' % instance.name,
        'res_model': 'woo.product',
        'view_mode': 'tree,form',
        'domain': [('instance_id', '=', instance.id)],
        'context': {'default_instance_id': instance.id},
    }
